/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_add_menu_item`(
    IN p_restaurant_id INT, IN p_owner_user_id INT, IN p_item_name VARCHAR(255), 
    IN p_desc VARCHAR(500), IN p_price DECIMAL(10,2)
)
BEGIN
    IF (SELECT owner_user_id FROM eats.restaurant WHERE restaurant_id = p_restaurant_id) != p_owner_user_id THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Permission Denied.';
    END IF;

    INSERT INTO eats.menu_item (restaurant_id, item_name, description, price, is_available)
    VALUES (p_restaurant_id, p_item_name, p_desc, p_price, 1);
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
