/*!50003 DROP PROCEDURE IF EXISTS `sp_add_review` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_add_review`(
    IN p_order_id INT, IN p_customer_user_id INT, IN p_rating INT, IN p_comment VARCHAR(500)
)
BEGIN
    IF (SELECT customer_user_id FROM eats.order WHERE order_id = p_order_id) != p_customer_user_id THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'You can only review your own orders.';
    ELSEIF (SELECT order_status_id FROM eats.order WHERE order_id = p_order_id) != 5 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Only delivered orders can be reviewed.';
    ELSEIF EXISTS (SELECT 1 FROM eats.review WHERE order_id = p_order_id) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Order already reviewed.';
    ELSE
        INSERT INTO eats.review (order_id, rating, comment) VALUES (p_order_id, p_rating, p_comment);
    END IF;
END ;;
DELIMITER ;
