DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_delete_cart_item`(IN p_cart_item_id INT)
BEGIN
    DELETE FROM eats.cart_item WHERE cart_item_id = p_cart_item_id;
END ;;
