CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_delete_menu_item`(
    IN p_menu_item_id INT
)
BEGIN
    -- Clear associated records from active carts first to prevent Foreign Key constraints from failing
    -- Note: Historical order_items are unaffected as they use snapshots and do not have a hard FK constraint
    DELETE FROM eats.cart_item WHERE menu_item_id = p_menu_item_id;
    
    -- Perform the actual physical deletion of the menu item
    DELETE FROM eats.menu_item WHERE menu_item_id = p_menu_item_id;
END ;;
