CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_monthly_top_rated_restaurant`(IN p_year INT, IN p_month INT)
BEGIN
  SELECT 
        r.restaurant_id, 
        r.name AS restaurant_name, 
        AVG(rv.rating) AS avg_rating, 
        COUNT(rv.review_id) AS total_reviews  
    FROM eats.restaurant r
    JOIN eats.order o ON r.restaurant_id = o.restaurant_id
    JOIN eats.review rv ON o.order_id = rv.order_id
    WHERE YEAR(rv.created_at) = p_year 
      AND MONTH(rv.created_at) = p_month  
    GROUP BY r.restaurant_id, r.name
    ORDER BY 
        avg_rating DESC,    
        total_reviews DESC   
    LIMIT 10;
END ;;
DELIMITER ;
