/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_process_checkout`(
    IN p_user_id INT, 
    IN p_cart_id INT,       -- Improved: Pass specific cart_id instead of guessing
    IN p_address_id INT, 
    IN p_payment_method VARCHAR(50)
)
BEGIN
    DECLARE v_restaurant_id INT; 
    DECLARE v_order_id INT;
    DECLARE v_total DECIMAL(10,2); 
    DECLARE v_address VARCHAR(500); 
    DECLARE v_postcode VARCHAR(6);
    DECLARE v_assigned_driver_id INT;
    DECLARE v_msg TEXT;

    -- Standard Transaction Handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN 
        GET DIAGNOSTICS CONDITION 1 v_msg = MESSAGE_TEXT;
        ROLLBACK; 
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_msg; 
    END;

    START TRANSACTION;

    -- 1. VALIDATION: Check if the cart belongs to this user and get restaurant info
    SELECT restaurant_id INTO v_restaurant_id 
    FROM eats.cart 
    WHERE cart_id = p_cart_id AND user_id = p_user_id;

    IF v_restaurant_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: Invalid cart selected or access denied.';
    END IF;

    -- 2. GET ADDRESS SNAPSHOT
    SELECT address, postal_code INTO v_address, v_postcode 
    FROM eats.address WHERE address_id = p_address_id AND user_id = p_user_id;

    IF v_address IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: Address not found or does not belong to user.';
    END IF;

    -- 3. CREATE ORDER
    INSERT INTO eats.order (customer_user_id, restaurant_id, customer_address_snapshot, customer_postcode_snapshot, order_status_id)
    VALUES (p_user_id, v_restaurant_id, v_address, v_postcode, 1);
    SET v_order_id = LAST_INSERT_ID();

    -- 4. SNAPSHOT ITEMS & CALCULATE TOTAL
    INSERT INTO eats.order_item (order_id, item_name, quantity, price_snapshot)
    SELECT v_order_id, m.item_name, c.quantity, m.price 
    FROM eats.cart_item c 
    JOIN eats.menu_item m ON c.menu_item_id = m.menu_item_id 
    WHERE c.cart_id = p_cart_id;
    
    SELECT SUM(quantity * price_snapshot) INTO v_total FROM eats.order_item WHERE order_id = v_order_id;

    -- 5. PAYMENT
    INSERT INTO eats.payment (order_id, amount, method, paid_at) 
    VALUES (v_order_id, v_total, p_payment_method, NOW());
    
    UPDATE eats.order SET order_status_id = 2 WHERE order_id = v_order_id;

    -- 6. AUTO-ASSIGN DRIVER (Least Busy Rider)
    SELECT u.user_id INTO v_assigned_driver_id 
    FROM eats.user u 
    LEFT JOIN eats.delivery d ON u.user_id = d.driver_user_id AND d.delivery_status_id != 3 
    WHERE u.role_id = 3 
    GROUP BY u.user_id 
    ORDER BY COUNT(d.delivery_id) ASC 
    LIMIT 1;

    IF v_assigned_driver_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: No riders available to accept this order.';
    END IF;

    INSERT INTO eats.delivery (order_id, driver_user_id, delivery_status_id, assigned_time) 
    VALUES (v_order_id, v_assigned_driver_id, 1, NOW());
    
    -- 7. CLEANUP: Delete the specific cart and its items
    DELETE FROM eats.cart_item WHERE cart_id = p_cart_id;
    DELETE FROM eats.cart WHERE cart_id = p_cart_id;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
