CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_register_restaurant`(
    IN p_owner_user_id INT, IN p_name VARCHAR(255), IN p_desc VARCHAR(500), 
    IN p_contact VARCHAR(8), IN p_address VARCHAR(500), IN p_postal VARCHAR(6)
)
BEGIN
    DECLARE v_restaurant_id INT;
    
    -- Error handling and automatic rollback
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN 
        ROLLBACK; 
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Registration failed. Transaction rolled back.'; 
    END;
    
    -- Verify permission: Only users with role_id 2 (Restaurant Owner) can register
    IF (SELECT role_id FROM eats.user WHERE user_id = p_owner_user_id) != 2 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Permission Denied. Only Restaurant Owners can register a restaurant.';
    END IF;

    START TRANSACTION;
    
    INSERT INTO eats.restaurant (owner_user_id, name, description, contact_no, is_open)
    VALUES (p_owner_user_id, p_name, p_desc, p_contact, 0);
    
    SET v_restaurant_id = LAST_INSERT_ID();
    
    INSERT INTO eats.address (restaurant_id, address, postal_code)
    VALUES (v_restaurant_id, p_address, p_postal);
    
    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_register_user` */;
