CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_register_user`(
    IN p_name VARCHAR(100), IN p_email VARCHAR(255), IN p_phone VARCHAR(8),
    IN p_password_hash VARCHAR(255), IN p_password_salt VARCHAR(255), IN p_role_id INT
)
BEGIN
    IF EXISTS (SELECT 1 FROM eats.user WHERE email = p_email) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: Email already registered.';
    ELSE
        INSERT INTO eats.user (name, email, phone, password_hash, password_salt, role_id)
        VALUES (p_name, p_email, p_phone, p_password_hash, p_password_salt, p_role_id);
    END IF;
END ;;
