CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_retrieve_customer_orders`(IN p_customer_user_id INT)
BEGIN
   SELECT 
        o.order_id,
        o.restaurant_id,
        r.name AS restaurant_name,
        o.customer_address_snapshot AS delivery_address,
        os.status_name AS current_status,  -- The human-readable label
        o.created_at AS order_time
    FROM eats.order o
    JOIN eats.order_status os ON o.order_status_id = os.order_status_id
    JOIN eats.restaurant r ON o.restaurant_id = r.restaurant_id
    WHERE o.customer_user_id = p_customer_user_id 
    ORDER BY 
        o.order_status_id ASC,  -- Keeps active orders at the top
        o.created_at DESC;      -- Shows newest orders first
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
