CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_retrieve_driver_pending_orders`(IN p_driver_user_id INT)
BEGIN
    -- -------------------------------------------------------------------------
    -- This SP retrieves active tasks for a specific rider.
    -- It joins with 'delivery_status' to show human-readable status names.
    -- Logic: Filters for Pending Pickup (1) or In Transit (2).
    -- -------------------------------------------------------------------------
    SELECT 
        d.delivery_id,
        d.order_id,
        ds.status_name AS delivery_status, -- The human-readable label
        d.assigned_time,
        o.customer_address_snapshot AS delivery_address,
        o.customer_postcode_snapshot AS postal_code
    FROM eats.delivery d
    JOIN eats.delivery_status ds ON d.delivery_status_id = ds.delivery_status_id
    JOIN eats.order o ON d.order_id = o.order_id
    WHERE d.driver_user_id = p_driver_user_id 
      AND d.delivery_status_id IN (1, 2)
    ORDER BY d.assigned_time ASC;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
