CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_retrieve_order_details`(IN p_order_id INT)
BEGIN
    -- Gets full receipt details including items, payment, and delivery status
    SELECT o.order_id, o.created_at, os.status_name AS order_status, 
           p.amount AS total_paid, p.method AS payment_method, ds.status_name AS delivery_status
    FROM eats.order o
    JOIN eats.order_status os ON o.order_status_id = os.order_status_id
    JOIN eats.payment p ON o.order_id = p.order_id
    LEFT JOIN eats.delivery d ON o.order_id = d.order_id
    LEFT JOIN eats.delivery_status ds ON d.delivery_status_id = ds.delivery_status_id
    WHERE o.order_id = p_order_id;
    
    -- Select Order Items
    SELECT item_name, quantity, price_snapshot FROM eats.order_item WHERE order_id = p_order_id;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
