DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_retrieve_restaurant_pending_orders`(IN p_restaurant_id INT)
BEGIN
    SELECT 
        o.order_id,
        u.name AS customer_name,     
        os.status_name AS order_status,
        o.created_at AS received_at,
        o.customer_address_snapshot AS delivery_address
    FROM eats.order o
    INNER JOIN eats.order_status os ON o.order_status_id = os.order_status_id
    INNER JOIN eats.user u ON o.customer_user_id = u.user_id
    WHERE o.restaurant_id = p_restaurant_id 
      AND o.order_status_id IN (1, 2) 
    ORDER BY o.created_at ASC;
END ;;
DELIMITER ;
