CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_search_restaurant`(
    IN p_keyword VARCHAR(100)
)
BEGIN
    SELECT DISTINCT r.restaurant_id, r.name 
    FROM eats.restaurant r
    LEFT JOIN eats.menu_item m ON r.restaurant_id = m.restaurant_id
    WHERE r.is_open = 1 AND (r.name LIKE CONCAT('%', p_keyword, '%') OR r.description LIKE CONCAT('%', p_keyword, '%')  OR m.item_name LIKE CONCAT('%', p_keyword, '%') OR m.description LIKE CONCAT('%', p_keyword, '%') );
END ;;
DELIMITER ;
