CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_update_delivery_status`(
    IN p_order_id INT, 
    IN p_delivery_status_id INT
)
BEGIN
    DECLARE v_msg TEXT;
    
    -- Error Handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN 
        GET DIAGNOSTICS CONDITION 1 v_msg = MESSAGE_TEXT;
        ROLLBACK; 
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_msg; 
    END;

    START TRANSACTION;

    -- 1. Update the Delivery Table
    UPDATE eats.delivery 
    SET delivery_status_id = p_delivery_status_id,
        -- If status is Delivered (3), we record the time
        delivered_time = CASE WHEN p_delivery_status_id = 3 THEN NOW() ELSE delivered_time END
    WHERE order_id = p_order_id;

    -- 2. AUTOMATIC SYNC: Update the Order Table based on Delivery Status
    -- Delivery Status 2 (Out for Delivery) -> Order Status 4 (In Transit)
    -- Delivery Status 3 (Delivered)        -> Order Status 5 (Completed)
    
    IF p_delivery_status_id = 2 THEN
        UPDATE eats.order SET order_status_id = 4 WHERE order_id = p_order_id;
    ELSEIF p_delivery_status_id = 3 THEN
        UPDATE eats.order SET order_status_id = 5 WHERE order_id = p_order_id;
    END IF;

    COMMIT;
END ;;
DELIMITER ;
