CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_update_restaurant`(
    IN p_restaurant_id INT, IN p_owner_user_id INT, IN p_name VARCHAR(255), 
    IN p_desc VARCHAR(500), IN p_contact VARCHAR(8), IN p_is_open TINYINT
)
BEGIN
    -- sp_verify_permission Logic Embedded: Check ownership
    IF (SELECT owner_user_id FROM eats.restaurant WHERE restaurant_id = p_restaurant_id) != p_owner_user_id THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Permission Denied: You do not own this restaurant.';
    END IF;

    UPDATE eats.restaurant 
    SET name = p_name, description = p_desc, contact_no = p_contact, is_open = p_is_open
    WHERE restaurant_id = p_restaurant_id;
END ;;
DELIMITER ;
