CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_upsert_cart_item`(
    IN p_user_id INT, 
    IN p_restaurant_id INT, 
    IN p_menu_item_id INT, 
    IN p_quantity INT
)
BEGIN
    DECLARE v_cart_id INT;
    DECLARE v_error_msg TEXT; -- Variable to hold the captured error message
    
    -- -------------------------------------------------------------------------
    -- ERROR HANDLER: Transactional Safety
    -- -------------------------------------------------------------------------
    -- This handler catches all SQL exceptions. It retrieves the specific 
    -- error message (e.g., "Cannot mix restaurants") before performing a 
    -- ROLLBACK, ensuring the user sees the actual cause of failure.
    -- -------------------------------------------------------------------------
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN 
        -- Capture the message from the diagnostic area
        GET DIAGNOSTICS CONDITION 1 v_error_msg = MESSAGE_TEXT;
        
        -- Undo any changes made during this failed transaction
        ROLLBACK; 
        
        -- Re-throw the original error message back to the application/demo
        IF v_error_msg IS NULL THEN SET v_error_msg = 'an error happened in cart operation.'; END IF;
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_error_msg;
    END;

    START TRANSACTION;

    -- 1. CART IDENTIFICATION
    -- If no cart exists, v_cart_id will be set to NULL.
    SELECT cart_id INTO v_cart_id 
    FROM eats.cart 
    WHERE user_id = p_user_id AND restaurant_id = p_restaurant_id LIMIT 1;
    
    -- 2. CART CREATION & VALIDATION
    IF v_cart_id IS NULL THEN
        -- BUSINESS RULE: A user cannot add items from a second restaurant 
        -- if an active cart already exists for a different restaurant.
        IF EXISTS (SELECT 1 FROM eats.cart WHERE user_id = p_user_id) THEN
            SIGNAL SQLSTATE '45000' 
            SET MESSAGE_TEXT = 'Error: Cannot mix items from different restaurants. Please clear your current cart first.';
        ELSE
            -- No cart found for this user at all; create a new one
            INSERT INTO eats.cart (user_id, restaurant_id) VALUES (p_user_id, p_restaurant_id);
            SET v_cart_id = LAST_INSERT_ID();
        END IF;
    END IF;

    -- 3. ITEM UPSERT (Update or Insert)
    -- Check if this specific food item is already in the cart
    IF EXISTS (SELECT 1 FROM eats.cart_item WHERE cart_id = v_cart_id AND menu_item_id = p_menu_item_id) THEN
        -- Update logic: Increment the existing quantity
        UPDATE eats.cart_item 
        SET quantity = quantity + p_quantity 
        WHERE cart_id = v_cart_id AND menu_item_id = p_menu_item_id;
    ELSE
        -- Insert logic: Add the new item to the cart
        INSERT INTO eats.cart_item (cart_id, menu_item_id, quantity) 
        VALUES (v_cart_id, p_menu_item_id, p_quantity);
    END IF;

    -- All operations succeeded; persist changes to the database
    COMMIT;
END ;;
DELIMITER ;
