-- ==============================================================================
-- UTILITY SCRIPT: Dynamic Time Synchronization
-- ==============================================================================
-- [Explanation]: Our dummy data was generated with a baseline of March 2026.
-- This script auto-updates our historical dummy data to the current month. 
-- It ensures our business reports always look real and up-to-date."

-- 1. Disable Safe Mode
SET SQL_SAFE_UPDATES = 0;

-- 2. Calculate the dynamic offset in months
-- Formula: (Current Year - Baseline Year) * 12 + (Current Month - Baseline Month)
SET @month_offset = (YEAR(CURRENT_DATE()) - 2026) * 12 + (MONTH(CURRENT_DATE()) - 3);

-- 3. Shift all historical data forward by the calculated offset
UPDATE eats.order 
SET created_at = DATE_ADD(created_at, INTERVAL @month_offset MONTH);

UPDATE eats.payment 
SET paid_at = DATE_ADD(paid_at, INTERVAL @month_offset MONTH);

UPDATE eats.delivery 
SET assigned_time = DATE_ADD(assigned_time, INTERVAL @month_offset MONTH),
    delivered_time = DATE_ADD(delivered_time, INTERVAL @month_offset MONTH)
WHERE assigned_time IS NOT NULL;

UPDATE eats.review 
SET created_at = DATE_ADD(created_at, INTERVAL @month_offset MONTH);

-- 4. Re-enable Safe Mode
SET SQL_SAFE_UPDATES = 1;

